<template>
  <v-dialog v-model="dialog.show" persistent max-width="780px">
    <v-card>
      <v-card-title>
        <div class="title">
          {{ $vuetify.lang.t(messages.title) }}
        </div>
      </v-card-title>
      <v-divider class="mx-4"></v-divider>
      <v-form>
        <v-card-text>
          <v-container>
            <v-row wrap>
              <v-col cols="12" sm="6" class="mb-0 py-0">
                  <v-select
                    v-model="form.type"
                    color="primary"
                    clearable
                    :items="optionType.type_season"
                    @blur="$v.form.type.$touch()"
                  @input="$v.form.type.$touch()"
                  :error-messages="typeErrors"
                    :label="$vuetify.lang.t('$vuetify.season.cols.type.title')"
                    prepend-inner-icon="mdi-account-group-outline mdi-dark mdi-18px"
                    class="font-weight-bold"
                    outlined
                    dense
                  ><template #label>
                    {{ $vuetify.lang.t("$vuetify.season.cols.type.title")
                    }}<span class="red--text"></span>
                  </template></v-select>
                </v-col>
                <v-col cols="12" sm="6" class="mb-0 py-0">
                <v-switch
                  v-model="is_active"
                  color="primary"
                  style="margin-top: -0px"
                  :label="$vuetify.lang.t('$vuetify.season.cols.is_active.title')"
                  outlined
                  dense
                ></v-switch>
              </v-col>
              <v-col cols="12">
                  <v-card class="pa-4" outlined>
                    <!-- Header -->
                    <div class="d-flex align-center justify-space-between mb-4">
                      <div>
                        <div class="text-h6 font-weight-bold">
                          {{ $vuetify.lang.t("$vuetify.dish.language") }}
                        </div>
                        <div class="grey--text text--darken-1 text-caption">
                          {{
                            $vuetify.lang.t(
                              "$vuetify.dish.language_description"
                            )
                          }}
                        </div>
                      </div>

                      <v-btn color="primary" small @click="addColumnLanguage">
                        <v-icon left>mdi-plus</v-icon>
                        {{ $vuetify.lang.t("$vuetify.btn.add") }}
                      </v-btn>
                    </div>

                    <v-divider class="mb-4"></v-divider>

                    <!-- Lines -->
                    <v-card
                      v-for="(rule, index) in name_language"
                      :key="index"
                      class="mb-2 pa-2 rounded-lg"
                      outlined
                    >
                      <v-row dense align="center">
                        <!-- Language -->
                        <v-col cols="4">
                          <v-select
                            v-model="rule.language"
                            :items="optionLanguage.type_language"
                            item-text="text"
                            item-value="value"
                            outlined
                            dense
                            hide-details
                            :label="
                              $vuetify.lang.t(
                                '$vuetify.dish.cols.language.title'
                              )
                            "
                          />
                        </v-col>

                        <!-- Name -->
                        <v-col cols="7">
                          <v-text-field
                            v-model="rule.name"
                            outlined
                            dense
                            hide-details
                            :label="
                              $vuetify.lang.t('$vuetify.dish.cols.name.title')
                            "
                          />
                        </v-col>

                        <!-- Actions -->
                        <v-col cols="1" class="d-flex justify-end">
                          <!-- Save -->
                          <!-- <v-btn icon @click="saveLanguage(rule)">
                            <v-icon :color="rule.saved ? 'green' : ''">
                              mdi-content-save
                            </v-icon>
                          </v-btn> -->

                          <!-- Delete -->
                          <v-btn
                            icon
                            color="error"
                            @click="removeColumnLanguage(index)"
                          >
                            <v-icon>mdi-delete-outline</v-icon>
                          </v-btn>
                        </v-col>
                      </v-row>
                    </v-card>
                  </v-card>
                </v-col>
              
              <v-col cols="12" sm="6" class="mb-0 py-0">
                <v-menu
                  v-model="menu"
                  :close-on-content-click="false"
                  transition="scale-transition"
                  offset-y
                  min-width="290px"
                >
                  <template v-slot:activator="{ on, attrs }">
                    <v-text-field
                      v-model="form.start_date"
                      color="primary"
                      outlined
                      dense
                      readonly
                      v-bind="attrs"
                      class="font-weight-bold"
                      v-on="on"
                    >
                      <template #label>
                        {{
                          $vuetify.lang.t(
                            "$vuetify.season.cols.start_date.title"
                          )
                        }}
                        <span class="red--text"><strong>*</strong></span>
                      </template>
                    </v-text-field>
                  </template>

                  <v-card>
                    <v-date-picker
                      v-if="!menuTime"
                      v-model="form.start_date"
                      color="primary"
                      @input="menuTime = true"
                    />

                    <!-- <v-time-picker
                      v-else
                      v-model="time"
                      color="primary"
                      format="24hr"
                      @click:minute="saveDateTime"
                    /> -->
                  </v-card>
                </v-menu>
              </v-col>
              <v-col cols="12" sm="6" class="mb-0 py-0">
                <v-menu
                  v-model="menu2"
                  :close-on-content-click="false"
                  transition="scale-transition"
                  offset-y
                  min-width="290px"
                >
                  <template v-slot:activator="{ on, attrs }">
                    <v-text-field
                      v-model="form.end_date"
                      color="primary"
                      outlined
                      class="font-weight-bold"
                      dense
                      readonly
                      v-bind="attrs"
                      v-on="on"
                    >
                      <template #label>
                        {{
                          $vuetify.lang.t("$vuetify.season.cols.end_date.title")
                        }}
                        <span class="red--text"></span>
                      </template>
                    </v-text-field>
                  </template>

                  <v-card>
                    <v-date-picker
                      v-if="!menuTime2"
                      v-model="form.end_date"
                      color="primary"
                      @input="menuTime2 = true"
                    />

                    <!-- <v-time-picker
                      v-else
                      v-model="time2"
                      color="primary"
                      format="24hr"
                      @click:minute="saveDateTime2"
                    /> -->
                  </v-card>
                </v-menu>
              </v-col>
            </v-row>
          </v-container>
        </v-card-text>
        <v-divider class="mx-4" style="margin-top: -25px"></v-divider>
        <v-card-actions style="margin-bottom: -5px">
          <v-spacer></v-spacer>
          <v-btn @click="forceRefresh">
            {{ $vuetify.lang.t("$vuetify.btn.close") }}
          </v-btn>

          <v-btn color="primary" :loading="loading" @click="save">
            {{ $vuetify.lang.t(messages.submit) }}
          </v-btn>
        </v-card-actions>
      </v-form>
    </v-card>
  </v-dialog>
</template>

<script>
import FormMixin from "./../../mixins/Common/Form.vue";
// import {mapGetters} from "vuex";
import { required } from "vuelidate/lib/validators";
export default {
  mixins: [FormMixin],
  props: {
    form: {
      type: Object,
      default: function () {
        return {
          id: null,
          name_language: null,
          organizer: null,
          start_date: null,
          end_date: null,
          type: null,
          is_active: null,
        };
      },
    },
  },
  data: () => ({
    maxDate: new Date().toISOString().substr(0, 10),
    e1: 1,
    isLoading: false,
    dialogForm: {
      show: false,
      shows: {
        showFilter: false,
        showInfo: false,
      },
    },
    menu: false,
    menuTime: false,
    date: null,
    time: null,
    menu2: false,
    menuTime2: false,
    date2: null,
    time2: null,
    is_active: true,
    urlItems: "seasons",
    isLoadingBills: false,
    optionLanguage: {
      type_language: [],
    },
    name_language: [],
    optionsLanguages: {
      text: {
        language: "",
        name: "",
        saved: false,
      },
    },
    searchBills: null,
    itemsBills: [],
    urlBills: "bills",
    optionType: {
      type_season: [],
    },
  }),
  watch: {
    searchBills(value) {
      if (value === null) return;
      this.isLoadingBills = true;
      const params = { code: value, bill_type: "EVENT" };
      let self = this;
      this.$store
        .dispatch("request", {
          url: self.urlBills,
          params: params,
        })
        .then((response) => {
          
          self.itemsBills = response.data.content;
        })
        .finally(() => (this.isLoadingBills = false));
    },
  },
  created() {
    //this.setItemRoles();
     this.getOptionsSeason();
     this.getOptionsLanguage();
  },
  validations() {
    let validators = {
      form: {
        start_date: {
          required,
        },
        end_date: {
          required,
        },
        type: {
          required,
        },
      },
    };
    return validators;
  },
  methods: {
    getOptionsSeason() {
      // On pouvait aussi utliser le forEach au lieu de   _.eaach
      let self = this;
      this._.each(this.$store.getters.season, (type_season) => {
        self.optionType.type_season.push({
          text: self.$vuetify.lang.t(type_season.text),
          value: type_season.value,
        });
      });
    },
      getOptionsLanguage() {
      // On pouvait aussi utliser le forEach au lieu de   _.eaach
      let self = this;
      this._.each(this.$store.getters.type_language, (type_language) => {
        self.optionLanguage.type_language.push({
          text: self.$vuetify.lang.t(type_language.text),
          value: type_language.value,
        });
      });
    },
    saveDateTime() {
      this.form.start_date = `${this.date} ${this.time}`;
      this.menu = false;
      this.menuTime = false;
    },
    saveDateTime2() {
      this.form.end_date = `${this.date2} ${this.time2}`;
      this.menu2 = false;
      this.menuTime2 = false;
    },
    closeModals() {
      this.dialog.show = false;
      this.e1 = 1;
    },
    // Fonction pour récuperer le contenu des champs du formulaire
    getDataForm() {
      let data = {
        is_active: this.is_active,
        type: this.form.type,
        end_date: this.form.end_date,
        start_date: this.form.start_date,
        name_language: this.name_language,
      };
      return data;
    },
    addColumnLanguage() {
      // this.uuid=uid();

      // Random UUID
      //       console.log(uid());
      this.name_language.push({
        ...this.optionsLanguages.text,
      });
    },
    removeColumnLanguage(index) {
      this.name_language.splice(index, 1);
    },
    forceRefresh() {
      this.dialog.show = false;
      this.name_language = [];
    },
    setForm(item) {
      this.is_active = item.is_active;
      // Données envoyées lors de la modification
      this.form.start_date = item.start_date;
      this.form.end_date = item.end_date;
      this.name_language = item.name_language;
      this.form.type = item.type;
      this.form.id = item.id;
      
    },
  },
  computed: {
    // Gestion des erreurs du formulaire
    nameErrors() {
      let errors = [];
      if (!this.$v.form.name.$dirty) return errors;

      !this.$v.form.name.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.name.required")
        );

      return errors;
    },
    organizerErrors() {
      let errors = [];
      if (!this.$v.form.organizer.$dirty) return errors;

      !this.$v.form.organizer.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.organizer.required")
        );

      return errors;
    },
    locationErrors() {
      let errors = [];
      if (!this.$v.form.location.$dirty) return errors;
      !this.$v.form.location.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.location.required")
        );
      return errors;
    },

    start_dateErrors() {
      let errors = [];
      if (!this.$v.form.start_date.$dirty) return errors;

      !this.$v.form.start_date.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.start_date.required")
        );
      return errors;
    },
    end_dateErrors() {
      let errors = [];
      if (!this.$v.form.end_date.$dirty) return errors;

      !this.$v.form.end_date.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.end_date.required")
        );
      return errors;
    },
    typeErrors() {
      let errors = [];
      if (!this.$v.form.type.$dirty) return errors;

      !this.$v.form.type.required &&
        errors.push(
          this.$vuetify.lang.t("$vuetify.event.cols.type.required")
        );
      return errors;
    },
  },
  components: {},
};
</script>
